import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input that contains path traversal characters

        String basePath = "data/"; // Base directory where files are allowed to be accessed
        String safePath = Paths.get(basePath, userInput).normalize().toString();

        if (!safePath.startsWith(basePath)) {
            System.out.println("Invalid file path.");
            return;
        }

        try {
            File file = new File(safePath);
            BufferedReader br = new BufferedReader(new FileReader(file));

            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }

            br.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

